namespace sv_cdf538af0e104798ae12814abe8d70f5.Services;

public class WarehouseInfo
{
    public string WarehouseId { get; set; } = "WH-001";
    public string WarehouseName { get; set; } = "Warehouse A";

    public static readonly IReadOnlyList<WarehouseInfo> All =
    [
        new() { WarehouseId = "WH-001", WarehouseName = "Warehouse A" },
        new() { WarehouseId = "WH-002", WarehouseName = "Warehouse B" },
        new() { WarehouseId = "WH-003", WarehouseName = "Warehouse C" },
    ];
}

namespace sv_cdf538af0e104798ae12814abe8d70f5.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Uses an event to notify all subscribed components when data changes.
/// Scoped lifetime ensures each user circuit gets its own instance.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
