@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@using sv_cdf538af0e104798ae12814abe8d70f5.Services

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap fw-semibold" for="warehouseSelect">Warehouse:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@_selectedId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseInfo.All)
        {
            <option value="@wh.WarehouseId">@wh.WarehouseName</option>
        }
    </select>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? CurrentWarehouse { get; set; }

    private string _selectedId = WarehouseInfo.All[0].WarehouseId;

    protected override void OnParametersSet()
    {
        if (CurrentWarehouse is not null)
            _selectedId = CurrentWarehouse.WarehouseId;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString() ?? WarehouseInfo.All[0].WarehouseId;
        var warehouse = WarehouseInfo.All.FirstOrDefault(w => w.WarehouseId == id)
                        ?? WarehouseInfo.All[0];

        _selectedId = warehouse.WarehouseId;
        await WarehouseSource.NotifyChangedAsync(warehouse);
    }
}

