@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable
@using sv_cdf538af0e104798ae12814abe8d70f5.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-4" style="max-width: 32rem;">
    <div class="card-body">
        <h5 class="card-title">
            <span class="bi bi-exclamation-triangle-fill me-2" aria-hidden="true"></span>
            Low-Stock Alerts for @(_warehouse?.WarehouseName ?? "—")
        </h5>
        <p class="card-text fs-4">
            Items below minimum level:
            <span class="badge rounded-pill @BadgeClass fs-5">@AlertService.LatestLowStockCount</span>
        </p>
        <p class="text-muted small mb-0">
            Refreshes every 10 seconds. Last update: @_lastRefresh.ToString("T")
        </p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? _warehouse { get; set; }

    private Action? _handler;
    private DateTime _lastRefresh = DateTime.Now;
    private string? _previousWarehouseId;

    private string BadgeClass => AlertService.LatestLowStockCount > 5
        ? "bg-danger" : AlertService.LatestLowStockCount > 0
        ? "bg-warning text-dark" : "bg-success";

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(() =>
        {
            _lastRefresh = DateTime.Now;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _handler;
    }

    protected override void OnParametersSet()
    {
        var currentId = _warehouse?.WarehouseId ?? WarehouseInfo.All[0].WarehouseId;

        if (_previousWarehouseId is null)
        {
            // First render — start polling
            _previousWarehouseId = currentId;
            AlertService.StartPolling(currentId);
        }
        else if (_previousWarehouseId != currentId)
        {
            // Warehouse changed — restart polling for the new warehouse
            _previousWarehouseId = currentId;
            AlertService.RestartPolling(currentId);
        }
    }

    public void Dispose()
    {
        if (_handler is not null)
            AlertService.OnAlertCountChanged -= _handler;
        AlertService.StopPolling();
    }
}

